BEGIN
    ALTER TABLE [HOSOXETHOCBONG] DROP CONSTRAINT [CHK_GPA_HoSo];
    ALTER TABLE [HOSOXETHOCBONG] ADD CONSTRAINT [CHK_GPA_HoSo] CHECK ([DiemHocTap] >= 0.0 AND [DiemHocTap] <= 10.0);
END
